I'm trying to shutdown _Datastore Emulator_ from Node.js:

```js
const options = {
    host: 'localhost',
    port: 8081,
    path: '/shutdown',
    method: 'POST',
};
http.request(options, ({ statusCode }) => {
    console.log(statusCode)
})
    .on('error', (err) => {
        console.log(err);
    })
    .end();
```

But most of the times I get 

```
{ Error: socket hang up
    at createHangUpError (_http_client.js:329:15)
    at Socket.socketOnEnd (_http_client.js:421:23)
    at emitNone (events.js:110:20)
    at Socket.emit (events.js:207:7)
    at endReadableNT (_stream_readable.js:1057:12)
    at _combinedTickCallback (internal/process/next_tick.js:138:11)
    at process._tickDomainCallback (internal/process/next_tick.js:218:9) code: 'ECONNRESET' }
```
which means that the emulator server closed the http connection before completing it properly. Rarely, I would get successful result with `200` status code -- which should be happening every time.

